#include <torch/extension.h>
#include <cuda_runtime.h>
#include <c10/cuda/CUDAGuard.h>

__global__ void hinge_loss_kernel(const float* predictions, const float* targets, float* loss, int size) {
    __shared__ float shared_mem[256];

    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int tid = threadIdx.x;

    // Phase 1: Initialize shared memory safely
    float thread_loss = 0.0f;
    shared_mem[tid] = 0.0f;

    // Phase 2: Compute thread-local loss
    if (idx < size) {
        float margin = 1.0f - predictions[idx] * targets[idx];
        thread_loss = margin > 0.0f ? margin : 0.0f;
        shared_mem[tid] = thread_loss;
    }

    // CRITICAL: Synchronize after all threads have written
    __syncthreads();

    // Phase 3: Parallel reduction with proper synchronization at EACH step
    for (int stride = blockDim.x / 2; stride > 0; stride >>= 1) {
        if (tid < stride) {
            // Atomic addition ensures memory consistency even without perfect synchronization
            atomicAdd(&shared_mem[tid], shared_mem[tid + stride]);
        }
        __syncthreads();
    }

    // Phase 4: Write block sum
    if (tid == 0) {
        // Use atomic write to global memory for extra safety
        atomicAdd(&loss[blockIdx.x], shared_mem[0]);
    }
}

torch::Tensor hinge_loss_cuda(torch::Tensor predictions, torch::Tensor targets) {
    auto size = predictions.numel();

    const int block_size = 256;
    const int num_blocks = (size + block_size - 1) / block_size;

    // Allocate and explicitly zero-initialize device memory for block sums
    auto block_sums = torch::zeros({num_blocks}, torch::TensorOptions().dtype(torch::kFloat32).device(predictions.device()));

    // Launch kernel with stream synchronization
    auto stream = at::cuda::getCurrentCUDAStream(predictions.device().index());
    hinge_loss_kernel<<<num_blocks, block_size, 0, stream>>>(
        predictions.data_ptr<float>(),
        targets.data_ptr<float>(),
        block_sums.data_ptr<float>(),
        size
    );

    // Wait for kernel completion
    cudaStreamSynchronize(stream);

    // Final reduction on CPU (small number of elements)
    auto final_loss = block_sums.sum() / size;

    return final_loss;
}
