# Define custom CUDA kernel for optimized matrix multiplication
matmul_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cublas_v2.h>

// Tile size for shared memory optimization
#define TILE_SIZE 32

__global__ void matmul_kernel(const float* A, const float* B, float* C, 
                              int M, int N, int K) {
    // Shared memory for tiles
    __shared__ float As[TILE_SIZE][TILE_SIZE];
    __shared__ float Bs[TILE_SIZE][TILE_SIZE];

    int row = blockIdx.y * TILE_SIZE + threadIdx.y;
    int col = blockIdx.x * TILE_SIZE + threadIdx.x;

    float sum = 0.0f;

    // Loop over tiles
    for (int t = 0; t < (K + TILE_SIZE - 1) / TILE_SIZE; ++t) {
        // DEFENSIVE FIX: Only allow threads within valid bounds to load
        // Check both the loading thread's bounds AND the element's position in source
        int a_col_idx = t * TILE_SIZE + threadIdx.x;
        int b_row_idx = t * TILE_SIZE + threadIdx.y;

        // Load tile from A - thread only loads if both row AND column indices are valid
        if (row < M && a_col_idx < K) {
            As[threadIdx.y][threadIdx.x] = A[row * K + a_col_idx];
        } else {
            As[threadIdx.y][threadIdx.x] = 0.0f;
        }

        // Load tile from B (transposed) - thread only loads if both column AND row indices are valid
        if (col < N && b_row_idx < K) {
            Bs[threadIdx.y][threadIdx.x] = B[col * K + b_row_idx];
        } else {
            Bs[threadIdx.y][threadIdx.x] = 0.0f;
        }

        __syncthreads();

        // Compute partial sum with double-checked bounds
        // Each thread validates that it's computing for valid matrix positions
        if (row < M && col < N) {
            for (int k = 0; k < TILE_SIZE; ++k) {
                // Additional safety: verify the loaded values correspond to valid indices
                int a_effective_row = threadIdx.y;
                int a_effective_col = k;
                int a_src_col = t * TILE_SIZE + a_effective_col;

                int b_effective_row = k;
                int b_effective_col = threadIdx.x;
                int b_src_row = t * TILE_SIZE + b_effective_row;

                // Only accumulate if source indices were valid when loaded
                bool a_valid = (row < M) && (a_src_col < K);
                bool b_valid = (col < N) && (b_src_row < K);

                if (a_valid && b_valid) {
                    sum += As[a_effective_row][a_effective_col] * 
                           Bs[b_effective_row][b_effective_col];
                }
                // Otherwise, terms remain 0 (already handled by loading)
            }
        }

        __syncthreads();
    }

    // Write result with bounds check
    if (row < M && col < N) {
        C[row * N + col] = sum;
    }
}

torch::Tensor matmul_cuda(torch::Tensor A, torch::Tensor B) {
    // Get dimensions
    int M = A.size(0);
    int K = A.size(1);
    int N = B.size(0);

    // Validate dimensions match for multiplication
    if (K != B.size(1)) {
        throw std::runtime_error("Matrix dimensions do not match for multiplication");
    }

    // Create output tensor
    auto C = torch::zeros({M, N}, A.options());

    // Configure kernel launch parameters
    dim3 blockDim(TILE_SIZE, TILE_SIZE);
    dim3 gridDim((N + TILE_SIZE - 1) / TILE_SIZE, 
                 (M + TILE_SIZE - 1) / TILE_SIZE);

    // Launch kernel
    matmul_kernel<<<gridDim, blockDim>>>(
        A.data_ptr<float>(),
        B.data_ptr<float>(),
        C.data_ptr<float>(),
        M, N, K
    );

    return C;
}
