matmul_optimized_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cublas_v2.h>
#include <cassert>

// Kernel for transposing matrix A (K, M) -> (M, K)
__global__ void transpose_A_kernel(const float* A, float* A_T, int K, int M) {
    // Linear thread index across entire grid
    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    int total_threads = gridDim.x * blockDim.x;

    // Process multiple elements per thread for better utilization
    for (int i = tid; i < M * K; i += total_threads) {
        if (i < M * K) {
            int row = i / K;      // Row in A_T (0..M-1)
            int col = i % K;      // Column in A_T (0..K-1)
            // A_T[row][col] = A[col][row]
            A_T[row * K + col] = A[col * M + row];
        }
    }
}

// Kernel for transposing matrix B (N, K) -> (K, N)
__global__ void transpose_B_kernel(const float* B, float* B_T, int N, int K) {
    // Linear thread index across entire grid
    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    int total_threads = gridDim.x * blockDim.x;

    // Process multiple elements per thread for better utilization
    for (int i = tid; i < K * N; i += total_threads) {
        if (i < K * N) {
            int row = i / N;      // Row in B_T (0..K-1)
            int col = i % N;      // Column in B_T (0..N-1)
            // B_T[row][col] = B[col][row]
            B_T[row * N + col] = B[col * K + row];
        }
    }
}

torch::Tensor matmul_optimized_cuda(torch::Tensor A, torch::Tensor B) {
    // Validate inputs
    assert(A.dim() == 2 && B.dim() == 2);
    assert(A.size(0) == B.size(0));  // K dimension must match

    // Get dimensions
    int K = A.size(0);
    int M = A.size(1);
    int N = B.size(0);

    // Create output tensor
    auto C = torch::zeros({M, N}, A.options());

    // Create transposed versions
    auto A_T = torch::zeros({M, K}, A.options());
    auto B_T = torch::zeros({K, N}, B.options());

    // Launch configuration for transpose kernels
    const int threads_per_block = 256;
    const int elements_A = M * K;
    const int elements_B = K * N;

    int blocks_A = (elements_A + threads_per_block - 1) / threads_per_block;
    int blocks_B = (elements_B + threads_per_block - 1) / threads_per_block;

    // Validate launch configuration
    assert(blocks_A > 0 && blocks_B > 0);
    assert(threads_per_block > 0);

    // Transpose A (K, M) -> (M, K) using 1D grid
    transpose_A_kernel<<<blocks_A, threads_per_block>>>(
        A.data_ptr<float>(),
        A_T.data_ptr<float>(),
        K, M
    );

    // Transpose B (N, K) -> (K, N) using 1D grid
    transpose_B_kernel<<<blocks_B, threads_per_block>>>(
        B.data_ptr<float>(),
        B_T.data_ptr<float>(),
        N, K
    );

    cudaDeviceSynchronize();

    // Use cuBLAS for matrix multiplication: C = A_T * B_T
    cublasHandle_t handle;
    cublasCreate(&handle);

    const float alpha = 1.0f;
    const float beta = 0.0f;

    // Note: cuBLAS expects column-major
    cublasSgemm(handle,
                CUBLAS_OP_N, CUBLAS_OP_N,
                N, M, K,  // Dimensions for column-major
                &alpha,
                B_T.data_ptr<float>(), N,
                A_T.data_ptr<float>(), K,
                &beta,
                C.data_ptr<float>(), N);

    cublasDestroy(handle);

    return C;
}
