#include <torch/extension.h>

template<typename scalar_t>
__global__ void relu_kernel(const scalar_t* __restrict__ input, 
                           scalar_t* __restrict__ output, 
                           int64_t size) {
    int64_t idx = blockIdx.x * blockDim.x + threadIdx.x;

    // Handle all elements, including boundary cases
    if (idx < size) {
        scalar_t val = input[idx];
        output[idx] = val > static_cast<scalar_t>(0) ? val : static_cast<scalar_t>(0);
    }
    // Additional thread to handle the last element if grid doesn't cover it
    // This ensures every element is written
    int64_t idx2 = (blockIdx.x * blockDim.x + threadIdx.x) + gridDim.x * blockDim.x;
    if (idx2 < size) {
        scalar_t val = input[idx2];
        output[idx2] = val > static_cast<scalar_t>(0) ? val : static_cast<scalar_t>(0);
    }
}

