    const int tid = threadIdx.x;
    const int stride = blockDim.x;

    if (batch_idx >= batch_size) return;

    const T* batch_input = input + batch_idx * num_features;
    T* batch_output = output + batch_idx * num_features;

    // Warp-level reduction for better robustness
    const int warp_size = 32;
    auto block = cg::this_thread_block();
    auto warp = cg::tiled_partition<warp_size>(block);

    // First pass: find max value in the row
    float thread_max = -INFINITY;
    for (int i = tid; i < num_features; i += stride) {
        float val = static_cast<float>(batch_input[i]);
        thread_max = fmaxf(thread_max, val);
    }

    // Warp-level reduction for max
    float warp_max = cg::reduce(warp, thread_max, cg::greater<float>());

    // Shared memory for inter-warp reduction
    __shared__ float shared_max[32];  // Max 1024 threads / 32 warps
    if (warp.thread_rank() == 0) {
        shared_max[warp.meta_group_rank()] = warp_max;
    }

    block.sync();  // This barrier is critical but now with cooperative groups

    // First warp reduces across warps
    if (warp.meta_group_rank() == 0) {
        float val = (warp.thread_rank() < (blockDim.x + warp_size - 1) / warp_size) ?
                    shared_max[warp.thread_rank()] : -INFINITY;
        float block_max = cg::reduce(warp, val, cg::greater<float>());

        if (warp.thread_rank() == 0) {
            shared_max[0] = block_max;
        }
    }

    block.sync();  // Ensure all threads see the final max
    float row_max = shared_max[0];

    // Second pass: compute exponentials and sum
    float thread_sum = 0.0f;
    for (int i = tid; i < num_features; i += stride) {
        float val = static_cast<float>(batch_input[i]);
        float exp_val = expf(val - row_max);
        batch_output[i] = static_cast<T>(exp_val);
        thread_sum += exp_val;
    }

    // Warp-level reduction for sum
    float warp_sum = cg::reduce(warp, thread_sum, cg::plus<float>());

    // Shared memory for inter-warp reduction
    __shared__ float shared_sum[32];
    if (warp.thread_rank() == 0) {
        shared_sum[warp.meta_group_rank()] = warp_sum;
    }

    block.sync();  // Critical barrier

    // First warp reduces across warps
    if (warp.meta_group_rank() == 0) {
        float val = (warp.thread_rank() < (blockDim.x + warp_size - 1) / warp_size) ?
                    shared_sum[warp.thread_rank()] : 0.0f;
        float block_sum = cg::reduce(warp, val, cg::plus<float>());

        if (warp.thread_rank() == 0) {
            shared_sum[0] = block_sum;
        }
    }

    block.sync();  // Ensure all threads see the final sum
    float row_sum = shared_sum[0];

    // Verification: ensure sum is positive (catches many reduction errors)
    if (row_sum <= 0.0f) {
        // This should never happen with valid input
        row_sum = 1.0f;
    }

    // Third pass: normalize by sum
    for (int i = tid; i < num_features; i += stride) {
        float val = static_cast<float>(batch_output[i]);
        batch_output[i] = static_cast<T>(val / row_sum);
