// Numerically stable max reduction with identity validation
template<typename T>
__device__ float stable_max_reduction(const T* input, int dim_size, int tid, int blockDim_x) {
    // Initialize with proper identity element for max
    const float MAX_IDENTITY = -std::numeric_limits<float>::infinity();
    float thread_max = MAX_IDENTITY;

    // First pass: find any finite value
    bool has_finite = false;
    for (int i = tid; i < dim_size; i += blockDim_x) {
        float val = to_float<T>(input[i]);
        if (isfinite(val)) {
            thread_max = fmaxf(thread_max, val);
            has_finite = true;
        }
    }

    __shared__ float sdata_max[1024];
    __shared__ bool sdata_has_finite[1024];

    sdata_max[tid] = thread_max;
    sdata_has_finite[tid] = has_finite;
    __syncthreads();

    // Reduction for max
    for (int s = blockDim_x / 2; s > 0; s >>= 1) {
        if (tid < s) {
            sdata_max[tid] = fmaxf(sdata_max[tid], sdata_max[tid + s]);
            sdata_has_finite[tid] = sdata_has_finite[tid] || sdata_has_finite[tid + s];
        }
        __syncthreads();
    }

    // If no finite values found, return -inf
    if (!sdata_has_finite[0]) {
        return -std::numeric_limits<float>::infinity();
    }

    return sdata_max[0];
}

