template<typename T>
__device__ float safe_inv_std(float variance, float eps) {
    float var_eps = variance + eps;
    // Original computes 1/sqrt(var_eps); maximum is 1/sqrt(eps) when variance=0
    float inv_std = rsqrtf(var_eps);
