# Define optimized CUDA kernel for L1 normalization with proper bounds checking
l1_norm_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cassert>

template<typename scalar_t>
__global__ void l1_normalize_kernel_robust(
    const scalar_t* __restrict__ input,
    scalar_t* __restrict__ output,
    const int batch_size,
    const int dim
) {
    // Calculate global thread index and total threads
    const int global_tid = blockIdx.x * blockDim.x + threadIdx.x;
    const int total_threads = gridDim.x * blockDim.x;

    // Shared memory for per-block reduction (one value per warp)
    __shared__ float warp_sums[32];

    // Each block processes one or more complete batches
    const int batches_per_block = (batch_size + gridDim.x - 1) / gridDim.x;
    const int start_batch = blockIdx.x * batches_per_block;
    const int end_batch = min(start_batch + batches_per_block, batch_size);

    // Process batches assigned to this block
    for (int batch_idx = start_batch; batch_idx < end_batch; ++batch_idx) {
        // Warp-level reduction for this batch
        const int warp_id = threadIdx.x / 32;
        const int lane_id = threadIdx.x % 32;

        // Compute L1 norm for this batch using block-stride loop
        float thread_sum = 0.0f;

        // Vectorized load for better throughput
        const int elements_per_thread = 4;
        const int vector_stride = blockDim.x * elements_per_thread;
        int elem_idx = threadIdx.x * elements_per_thread;

        while (elem_idx < dim) {
            const int load_idx = batch_idx * dim + elem_idx;
            if (elem_idx + 3 < dim) {
                // Load 4 elements at once
                const scalar_t val0 = input[load_idx];
                const scalar_t val1 = input[load_idx + 1];
                const scalar_t val2 = input[load_idx + 2];
                const scalar_t val3 = input[load_idx + 3];

                thread_sum += fabsf((float)val0) + fabsf((float)val1) +
                              fabsf((float)val2) + fabsf((float)val3);
            } else {
                // Handle remaining elements
                for (int i = 0; i < elements_per_thread && (elem_idx + i) < dim; ++i) {
                    thread_sum += fabsf((float)input[load_idx + i]);
                }
            }
            elem_idx += vector_stride;
        }

        // Warp-level reduction
        for (int offset = 16; offset > 0; offset >>= 1) {
            thread_sum += __shfl_down_sync(0xffffffff, thread_sum, offset);
        }

        // Store warp sum in shared memory
        if (lane_id == 0) {
            warp_sums[warp_id] = thread_sum;
        }
        __syncthreads();

        // Final reduction across warps (only first warp participates)
        float batch_sum = 0.0f;
        if (warp_id == 0) {
            float warp_sum = lane_id < (blockDim.x / 32) ? warp_sums[lane_id] : 0.0f;

            for (int offset = 16; offset > 0; offset >>= 1) {
                warp_sum += __shfl_down_sync(0xffffffff, warp_sum, offset);
            }

            if (lane_id == 0) {
                batch_sum = warp_sum;
                warp_sums[0] = batch_sum;  // Store for broadcast
            }
        }
        __syncthreads();

        // Broadcast batch_sum to all threads
        batch_sum = warp_sums[0];
        const float inv_batch_sum = (batch_sum == 0.0f) ? 1.0f : (1.0f / batch_sum);

        // Normalize and write output
        elem_idx = threadIdx.x * elements_per_thread;
        while (elem_idx < dim) {
            const int store_idx = batch_idx * dim + elem_idx;
            if (elem_idx + 3 < dim) {
                output[store_idx] = input[store_idx] * inv_batch_sum;
                output[store_idx + 1] = input[store_idx + 1] * inv_batch_sum;
                output[store_idx + 2] = input[store_idx + 2] * inv_batch_sum;
                output[store_idx + 3] = input[store_idx + 3] * inv_batch_sum;
            } else {
                for (int i = 0; i < elements_per_thread && (elem_idx + i) < dim; ++i) {
                    output[store_idx + i] = input[store_idx + i] * inv_batch_sum;
                }
            }
            elem_idx += vector_stride;
        }
        __syncthreads();  // Ensure all threads finish this batch before next
    }
}

