l2_norm_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <math.h>
#include <type_traits>

template<typename T>
struct ComputeType {
    using type = float;  // Default to float for accumulation
};

template<>
struct ComputeType<double> {
    using type = double;
};

template<>
struct ComputeType<half> {
    using type = float;
};

template<typename T>
__global__ void l2_norm_kernel(const T* __restrict__ input, T* __restrict__ output, 
                               int batch_size, int dim) {
    using ComputeT = typename ComputeType<T>::type;

    const int batch_idx = blockIdx.x;
    const int tid = threadIdx.x;

    // Use 256 threads per block (power of 2 for reduction)
    const int threads = 256;

    // Shared memory for reduction - use ComputeT for accumulation
    __shared__ ComputeT sdata[256];

    // Each thread processes multiple elements
    ComputeT thread_sum = 0.0;

    // Process elements with stride equal to total threads
    // Explicitly cast to ComputeT to ensure correct precision
    for (int i = tid; i < dim; i += threads) {
        int idx = batch_idx * dim + i;
        ComputeT val = static_cast<ComputeT>(input[idx]);
        thread_sum += val * val;
    }

    // Parallel reduction
    sdata[tid] = thread_sum;
    __syncthreads();

    // Tree reduction
    for (int stride = threads / 2; stride > 0; stride >>= 1) {
        if (tid < stride) {
            sdata[tid] += sdata[tid + stride];
        }
        __syncthreads();
    }

    // Compute reciprocal of L2 norm (1 / sqrt(sum))
    ComputeT scale = 0.0;
    if (tid == 0) {
        // Use epsilon of same type as ComputeT
        const ComputeT epsilon = static_cast<ComputeT>(1e-8);
        ComputeT norm = sqrt(sdata[0] + epsilon);
        scale = static_cast<ComputeT>(1.0) / norm;
        sdata[0] = scale;
    }
    __syncthreads();

    scale = sdata[0];

    // Normalize elements with explicit type conversion
    for (int i = tid; i < dim; i += threads) {
        int idx = batch_idx * dim + i;
        ComputeT val = static_cast<ComputeT>(input[idx]);
        output[idx] = static_cast<T>(val * scale);
    }
}

