# Define custom CUDA kernel for optimized sum reduction with keepdim=True
sum_reduction_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <stdio.h>
#include <cassert>

template<typename scalar_t>
__global__ void sum_reduction_kernel(
    const scalar_t* input,
    scalar_t* output,
    const int outer_size,
    const int reduce_size,
    const int inner_size,
    const int total_output_elements
) {
    // Calculate global thread ID using 1D grid
    const int tid = blockIdx.x * blockDim.x + threadIdx.x;

    // Early return if this thread is beyond the total output elements needed
    if (tid >= total_output_elements) {
        return;
    }

    // Calculate output indices from linear thread ID
    const int outer_idx = tid / inner_size;
    const int inner_idx = tid % inner_size;

    // Validate indices explicitly
    if (outer_idx >= outer_size || inner_idx >= inner_size) {
        // This should never happen if grid is properly configured
        // but we check defensively
        return;
    }

    const scalar_t* input_ptr = input + outer_idx * reduce_size * inner_size + inner_idx;
    scalar_t sum = 0;

    // Sequential reduction across reduce dimension
    for (int reduce_idx = 0; reduce_idx < reduce_size; reduce_idx++) {
        sum += input_ptr[reduce_idx * inner_size];
    }

    output[tid] = sum;
}

torch::Tensor sum_reduction_cuda(torch::Tensor input, int dim) {
    // Get tensor dimensions
    auto sizes = input.sizes();
    int ndim = input.dim();

    // Validate dimension
    if (dim < 0) dim += ndim;
    if (dim < 0 || dim >= ndim) {
        throw std::runtime_error("Invalid reduction dimension");
    }

    // Calculate sizes for the reduction
    int outer_size = 1;
    for (int i = 0; i < dim; i++) {
        outer_size *= sizes[i];
    }

    int reduce_size = sizes[dim];

    int inner_size = 1;
    for (int i = dim + 1; i < ndim; i++) {
        inner_size *= sizes[i];
    }

    // Prepare output tensor with keepdim=True
    std::vector<int64_t> output_sizes;
    for (int i = 0; i < ndim; i++) {
        if (i == dim) {
            output_sizes.push_back(1);
        } else {
            output_sizes.push_back(sizes[i]);
        }
    }

    auto output = torch::empty(output_sizes, input.options());

    // Calculate total output elements
    const int total_output_elements = outer_size * inner_size;

    // Validate that we have output elements to compute
    if (total_output_elements == 0) {
        return output;
    }

    // Launch kernel configuration
    // Use 1D grid that covers all output elements
    const int threads_per_block = 256;
    const int blocks = (total_output_elements + threads_per_block - 1) / threads_per_block;

    // Validate grid configuration
    if (blocks == 0 || blocks > 65535) {
        throw std::runtime_error("Invalid grid configuration for reduction kernel");
    }

    // Dispatch based on data type
    AT_DISPATCH_FLOATING_TYPES_AND_HALF(input.scalar_type(), "sum_reduction_cuda", [&] {
        sum_reduction_kernel<scalar_t><<<blocks, threads_per_block>>>(
            input.data_ptr<scalar_t>(),
            output.data_ptr<scalar_t>(),
            outer_size,
            reduce_size,
            inner_size,
            total_output_elements
        );
    });

    // Check for kernel launch errors
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        throw std::runtime_error(std::string("CUDA kernel launch error: ") + cudaGetErrorString(err));
    }

    return output;
}
"""

