    __syncthreads();

    // Final reduction across warps
    if (threadIdx.x < WARP_SIZE) {
        scalar_t val = (threadIdx.x < (blockDim.x + WARP_SIZE - 1) / WARP_SIZE) ? shared[threadIdx.x] : scalar_t(1.0);
        scalar_t block_product = warp_reduce_product(val);

