template<typename T>
__global__ void row_scan_kernel(const T* input, T* output, int rows, int cols) {
    int row = blockIdx.x;
    int tid = threadIdx.x;

    if (row >= rows) return;

    extern __shared__ T shared[];

    // Load row into shared memory with bounds checking
    for (int i = tid; i < cols; i += blockDim.x) {
        shared[i] = input[row * cols + i];
    }
    __syncthreads();

    // Robust Blelloch parallel scan adapted for arbitrary sizes
    // Up-sweep phase
    int offset = 1;
    for (int d = cols >> 1; d > 0; d >>= 1) {
        __syncthreads();
        if (tid < d) {
            int ai = offset * (2 * tid + 1) - 1;
            int bi = offset * (2 * tid + 2) - 1;
            if (bi < cols) {
                shared[bi] += shared[ai];
            }
        }
        offset <<= 1;
    }

    // Down-sweep phase
    if (tid == 0) {
        if (cols > 0) {
            shared[cols - 1] = T(0);
        }
    }

    for (int d = 1; d < cols; d <<= 1) {
        offset >>= 1;
        __syncthreads();

        if (tid < d) {
            int ai = offset * (2 * tid + 1) - 1;
            int bi = offset * (2 * tid + 2) - 1;
            if (bi < cols && ai < cols) {
                T t = shared[ai];
                shared[ai] = shared[bi];
                shared[bi] += t;
            }
        }
    }

    __syncthreads();

    // Store results with bounds checking
    for (int i = tid; i < cols; i += blockDim.x) {
        output[row * cols + i] = shared[i];
    }
