            if (bi < n) {
                temp[bi] += temp[ai];
            }
        }
        offset <<= 1;
        __syncthreads();
    }

    // Down-sweep phase with bounds checking
    if (tid == 0 && n > 0) {
        temp[n - 1] = 0;
    }
    __syncthreads();

    for (int d = 1; d <= blockDim.x; d <<= 1) {
        offset >>= 1;
        __syncthreads();

