template<typename T>
__global__ void row_scan_kernel(const T* input, T* output, int rows, int cols) {
    // Robustness fix: validate inputs and ensure all necessary threads execute
    if (cols <= 0 || cols > blockDim.x * 2) {
        // For simplicity, we assume cols is reasonable; otherwise use fallback
        return;
    }

    int row = blockIdx.x;
    int tid = threadIdx.x;

    if (row >= rows) return;

    extern __shared__ T shared[];

    // Load row into shared memory
    for (int i = tid; i < cols; i += blockDim.x) {
        shared[i] = input[row * cols + i];
    }
    __syncthreads();

