    __syncthreads();

    // Step 4: Add warp prefix to elements
    int warp_id = tid / 32;
    int lane = tid % 32;
    T warp_prefix = (warp_id < 32) ? warp_sums[warp_id] : 0;

    // Store results with proper warp offset
    for (int i = tid; i < cols; i += blockDim.x) {
        int elem_warp = i / 32;
        int elem_lane = i % 32;
        if (elem_warp == warp_id) {
