template<typename T>
__global__ void row_scan_kernel(const T* input, T* output, int rows, int cols) {
    int row = blockIdx.x;
    int tid = threadIdx.x;

    if (row >= rows) return;

    // Calculate padded size to next power of two for shared memory
    int padded_cols = next_power_of_two(cols);
    extern __shared__ T shared[];

    // Initialize shared memory (including padding) to zero
    for (int i = tid; i < padded_cols; i += blockDim.x) {
        shared[i] = T(0);
    }
    __syncthreads();

    // Load row into shared memory only within actual column bounds
    for (int i = tid; i < cols; i += blockDim.x) {
        shared[i] = input[row * cols + i];
    }
    __syncthreads();

    // Perform parallel inclusive scan (Blelloch algorithm) on padded size
    // Up-sweep phase
    for (int stride = 1; stride < padded_cols; stride <<= 1) {
        int idx = (tid + 1) * stride * 2 - 1;
        if (idx < padded_cols) {
            shared[idx] += shared[idx - stride];
        }
        __syncthreads();
    }

    // Clear last element for inclusive->exclusive conversion if needed
    if (tid == 0) {
        shared[padded_cols - 1] = T(0);
    }
    __syncthreads();

    // Down-sweep phase
    for (int stride = padded_cols >> 1; stride > 0; stride >>= 1) {
        int idx = (tid + 1) * stride * 2 - 1;
        if (idx < padded_cols) {
            T temp = shared[idx - stride];
            shared[idx - stride] = shared[idx];
            shared[idx] += temp;
        }
        __syncthreads();
    }

    // Store results (only actual columns)
    for (int i = tid; i < cols; i += blockDim.x) {
        output[row * cols + i] = shared[i];
    }
