    int bi = tid * 2 + 1;

    if (ai < n) temp[ai] = data[ai];
    if (bi < n) temp[bi] = data[bi];

    __syncthreads();

    // Up-sweep phase
    for (int d = n >> 1; d > 0; d >>= 1) {
        if (tid < d) {
            int ai = offset * (2 * tid + 1) - 1;
            int bi = offset * (2 * tid + 2) - 1;
            // Use volatile to force memory ordering and make races more observable
            volatile T* temp_vol = temp;
            temp_vol[bi] += temp_vol[ai];
        }
        offset <<= 1;
        __syncthreads();  // CRITICAL: Must complete all updates before next iteration

        // Debug validation for small n
        SCAN_ASSERT(tid >= d || offset <= n);
    }

    // Down-sweep phase
    if (tid == 0) {
        temp[n - 1] = 0;
    }

    for (int d = 1; d < n; d <<= 1) {
        offset >>= 1;
        __syncthreads();

        if (tid < d) {
            int ai = offset * (2 * tid + 1) - 1;
            int bi = offset * (2 * tid + 2) - 1;

            T t = temp[ai];
            temp[ai] = temp[bi];
            temp[bi] += t;
        }
    }

    __syncthreads();

    // Write results back to global memory
    if (ai < n) data[ai] = temp[ai];
    if (bi < n) data[bi] = temp[bi];
