template<typename T>
__global__ void row_scan_kernel(const T* input, T* output, int rows, int cols) {
    int row = blockIdx.x;
    int tid = threadIdx.x;

    if (row >= rows) return;

    extern __shared__ T shared[];

    // Load row into shared memory - ALL threads participate
    for (int i = tid; i < cols; i += blockDim.x) {
        shared[i] = input[row * cols + i];
    }
    __syncthreads();

    // Parallel reduction-based prefix scan instead of sequential
    // This ensures all threads participate and synchronization is necessary

    // Up-sweep (reduction) phase
    int stride = 1;
    while (stride < cols) {
        // Each thread handles two elements
        int idx1 = (2 * tid + 1) * stride - 1;
        int idx2 = (2 * tid + 2) * stride - 1;

        if (idx2 < cols && idx1 >= 0) {
            shared[idx2] += shared[idx1];
        }
        stride <<= 1;
        __syncthreads();
    }

    // Down-sweep phase
    if (tid == 0) {
        // Store last element for inclusive scan
        T last = shared[cols - 1];
        shared[cols - 1] = 0;
    }
    __syncthreads();

    stride = cols >> 1;
    while (stride > 0) {
        // Each thread handles two elements
        int idx1 = (2 * tid + 1) * stride - 1;
        int idx2 = (2 * tid + 2) * stride - 1;

        if (idx2 < cols && idx1 >= 0) {
            T temp = shared[idx1];
            shared[idx1] = shared[idx2];
            shared[idx2] += temp;
        }
        stride >>= 1;
        __syncthreads();
    }

    // For inclusive scan, add original value back
    if (tid == 0) {
        // First element already correct
        for (int i = 1; i < cols; i++) {
            shared[i] += shared[i - 1];
        }
    }
    __syncthreads();

    // Store results
    for (int i = tid; i < cols; i += blockDim.x) {
        output[row * cols + i] = shared[i];
    }
