    const int64_t total_threads = threads_per_block * gridDim.x * gridDim.y * gridDim.z;

    // Each thread handles one inner element per outer index
    for (int64_t idx = block_id * threads_per_block + thread_id; 
         idx < outer_size * inner_size; 
         idx += total_threads) {

        const int64_t outer_idx = idx / inner_size;
        const int64_t inner_idx = idx % inner_size;

        if (outer_idx >= outer_size || inner_idx >= inner_size) continue;

        const int64_t base_offset = outer_idx * dim_size * inner_size + inner_idx;
        const int64_t stride = inner_size;

        // Sequential cumulative product
        scalar_t prod = static_cast<scalar_t>(1.0);
        for (int64_t d = 0; d < dim_size; ++d) {
            scalar_t val = input[base_offset + d * stride];
            prod *= val;
