                    output.data_ptr<scalar_t>(),
                    outer_size,
                    dim_size,
                    inner_size
                );
            }
        })
    );

    // Check for CUDA errors
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        throw std::runtime_error("CUDA error in reverse_cumsum: " + 
                                std::string(cudaGetErrorString(err)));
    }

    return output;
