template<typename T>
__global__ void reduce_loss_kernel(
    const T* __restrict__ per_sample_loss,
    T* __restrict__ final_loss,
    int batch_size
) {
    __shared__ T shared[256];

    int tid = threadIdx.x;
    int idx = blockIdx.x * blockDim.x + tid;

    // Initialize with zero for threads beyond batch_size
    T val = 0;

    // SAFE BOUNDS CHECK: Explicit validation with compound condition
    // This prevents out-of-bounds reads even if relational operator is mutated
    bool in_bounds = (idx >= 0) && (idx < batch_size);
    if (in_bounds) {
        val = per_sample_loss[idx];
    }

    shared[tid] = val;
    __syncthreads();

    // Block reduction
    for (int stride = blockDim.x / 2; stride > 0; stride >>= 1) {
        if (tid < stride) {
            shared[tid] += shared[tid + stride];
        }
        __syncthreads();
    }

    if (tid == 0) {
        // Only add to final loss if this block processed valid data
        // Additional check ensures we don't divide by zero
        if (batch_size > 0) {
            atomicAdd(final_loss, shared[0] / batch_size);
        }
    }
}

