        if (i == target_idx) {
            sample_loss -= positive_weight * log_prob;
        } else {
            sample_loss -= negative_weight * log_prob;
        }
    }

    // Store per-sample loss for reduction
    loss[idx] = sample_loss;
}

template<typename T>
__global__ void reduce_loss_kernel(
    const T* __restrict__ per_sample_loss,
    T* __restrict__ final_loss,
    int batch_size
) {
    // Shared memory for block-level reduction
    __shared__ T shared[256];

    int tid = threadIdx.x;
    int idx = blockIdx.x * blockDim.x + tid;

    T val = 0;
    if (idx < batch_size) {
        val = per_sample_loss[idx];
    }

    // Warp-level reduction first
    T warp_sum = warp_reduce_sum(val);

    // Each warp's first thread writes to shared memory
    if ((tid & 31) == 0) {
        shared[tid / 32] = warp_sum;
    }

    // Synchronize to ensure all warps have written
    __syncthreads();

    // First warp reduces the per-warp sums
    if (tid < 32) {
        T block_sum = 0;
        int num_warps = (blockDim.x + 31) / 32;
        if (tid < num_warps) {
            block_sum = shared[tid];
        }

        // Final reduction within the first warp
        block_sum = warp_reduce_sum(block_sum);

        // First thread of the block performs atomic add
        if (tid == 0) {
            // Use atomic operation for thread safety
            cuda::atomic_ref<T, cuda::thread_scope_device> atomic_ref(*final_loss);
            atomic_ref.fetch_add(block_sum / batch_size, cuda::memory_order_relaxed);
        }
    }
}

