//                          L(diff) = |diff| - 0.5 * beta   otherwise
// These must match exactly or the loss function is incorrect.
#define QUADRATIC_COEFFICIENT 0.5f
#define LINEAR_COEFFICIENT 0.5f

// Static assertion to ensure coefficients are mathematically correct
// In CUDA device code, we use a compile-time check with ternary operator
namespace {
__device__ __constant__ float QUADRATIC_COEFF = QUADRATIC_COEFFICIENT;
__device__ __constant__ float LINEAR_COEFF = LINEAR_COEFFICIENT;
}

__global__ void smooth_l1_loss_kernel(
    const float* __restrict__ predictions,
    const float* __restrict__ targets,
    float* __restrict__ output,
    int total_elements,
    float beta
) {
    // Validate beta is positive (mathematical requirement)
    if (threadIdx.x == 0 && blockIdx.x == 0) {
        assert(beta > 0.0f && "beta must be positive for Smooth L1 Loss");
        // Verify coefficients are mathematically correct
        assert(QUADRATIC_COEFF == 0.5f && "Quadratic coefficient must be 0.5");
        assert(LINEAR_COEFF == 0.5f && "Linear coefficient must be 0.5");
    }
    __syncthreads();

    int idx = blockIdx.x * blockDim.x + threadIdx.x;

    if (idx < total_elements) {
        float diff = predictions[idx] - targets[idx];
        float abs_diff = fabsf(diff);

        if (abs_diff < beta) {
            // Quadratic region: 0.5 * diff^2 / beta
            output[idx] = QUADRATIC_COEFF * diff * diff / beta;
        } else {
            // Linear region: |diff| - 0.5 * beta
            output[idx] = abs_diff - LINEAR_COEFF * beta;
        }
    }
}

__global__ void sum_reduction_kernel(
    const float* __restrict__ input,
    float* __restrict__ output,
    int size
) {
    extern __shared__ float shared_mem[];

    int tid = threadIdx.x;
    int idx = blockIdx.x * blockDim.x + threadIdx.x;

    // Load data into shared memory
    if (idx < size) {
        shared_mem[tid] = input[idx];
    } else {
        shared_mem[tid] = 0.0f;
    }
    __syncthreads();

    // Parallel reduction
    for (int s = blockDim.x / 2; s > 0; s >>= 1) {
        if (tid < s) {
            shared_mem[tid] += shared_mem[tid + s];
        }
        __syncthreads();
    }

    // Write block sum to global memory
    if (tid == 0) {
        output[blockIdx.x] = shared_mem[0];
    }
}

