template<typename From, typename To>
__device__ To convert_to_compute_type(From value) {
    static_assert(std::is_same<From, float>::value, 
                  "Input type must be float32 for this kernel");
    static_assert(std::is_same<To, float>::value,
                  "Compute type must be float for this kernel");
