    cg::thread_block_tile<32> warp = cg::tiled_partition<32>(block);

    scalar_t thread_sum = 0.0f;
    scalar_t thread_valid = 0.0f;  // Track if computation was valid

    // Process elements with stride equal to total threads in block
    int tid = threadIdx.x;
    int total_threads = blockDim.x;

    for (int idx = tid; idx < seq_len; idx += total_threads) {
        scalar_t p = pred_batch[idx];
        scalar_t t = target_batch[idx];

        // Validate inputs at kernel level with explicit epsilon
        if (p <= 0.0f || t <= 0.0f) {
            // Invalid probability detected - kernel will handle this
            thread_valid = -1.0f;  // Mark as invalid
            continue;
