        int num_warps = (total_threads + 31) / 32;

        for (int i = warp.thread_rank(); i < num_warps; i += warp.size()) {
            block_sum += block_results[i].sum;
            block_valid = fmaxf(block_valid, block_results[i].valid);
        }

        scalar_t final_sum = cg::reduce(warp, block_sum, cg::plus<scalar_t>());
        scalar_t final_valid = cg::reduce(warp, block_valid, cg::max<scalar_t>());

